# ── PDF背景画像（base64）──
PDF_BG_IMAGE = ""

# PDF画像サイズ（dpi=150）
PDF_IMG_W = 1241
PDF_IMG_H = 1754

def make_pdf_island_map(df, target_machines=None, diff_override=None):
    """PDFを背景に差枚をオーバーレイした島図"""
    import plotly.graph_objects as go

    diff_map = {}
    for _, row in df.iterrows():
        if not np.isnan(row["台番"]):
            n = int(row["台番"])
            diff_map[n] = row["前日差枚"]
    if diff_override:
        for n, v in diff_override.items():
            diff_map[n] = v
    if target_machines is None:
        target_machines = set()

    fig = go.Figure()

    # 背景画像
    import base64
    fig.add_layout_image(
        dict(
            source=f"data:image/png;base64,{PDF_BG_IMAGE}",
            xref="x", yref="y",
            x=0, y=0,
            sizex=PDF_IMG_W, sizey=PDF_IMG_H,
            sizing="stretch",
            opacity=1.0,
            layer="below"
        )
    )

    shapes = []
    annotations = []
    BW = 24  # バッジ幅
    BH = 14  # バッジ高さ
    OFFSET_Y = 18  # 台番の上にずらすピクセル数

    for mno, (rx, ry) in PDF_POSITIONS.items():
        px = rx * PDF_IMG_W
        py = ry * PDF_IMG_H

        diff = diff_map.get(mno, np.nan)
        bg = diff_to_color(diff)
        text_c = diff_to_text_color(diff)
        is_target = mno in target_machines

        # データなしはスキップ
        if np.isnan(diff):
            if is_target:
                by = py - OFFSET_Y
                shapes.append(dict(
                    type="rect",
                    x0=px - BW/2 - 2, y0=by - BH/2 - 2,
                    x1=px + BW/2 + 2, y1=by + BH/2 + 2,
                    fillcolor="rgba(0,0,0,0)",
                    line=dict(color="#FFD700", width=2.5),
                    layer="above"
                ))
            continue

        by = py - OFFSET_Y  # 台番の上に配置

        border_c = "#FFD700" if is_target else ("rgba(200,0,0,0.9)" if diff <= -500 else "rgba(50,50,50,0.4)")
        border_w = 2.5 if is_target else (1.5 if diff <= -500 else 0.8)

        shapes.append(dict(
            type="rect",
            x0=px - BW/2, y0=by - BH/2,
            x1=px + BW/2, y1=by + BH/2,
            fillcolor=bg,
            opacity=0.92,
            line=dict(color=border_c, width=border_w),
            layer="above"
        ))

        if np.isnan(diff): diff_text = "?"
        elif diff > 0: diff_text = f"+{int(diff):,}"
        elif diff == 0: diff_text = "0"
        else: diff_text = f"{int(diff):,}"

        annotations.append(dict(
            x=px, y=by,
            text=f"<b>{diff_text}</b>",
            showarrow=False,
            font=dict(size=6, color=text_c),
            xanchor="center", yanchor="middle"
        ))

    fig.update_layout(
        width=PDF_IMG_W,
        height=PDF_IMG_H,
        paper_bgcolor="#0a0e1a",
        plot_bgcolor="rgba(0,0,0,0)",
        showlegend=False,
        margin=dict(l=0, r=0, t=0, b=0),
        xaxis=dict(visible=False, range=[0, PDF_IMG_W], scaleanchor="y"),
        yaxis=dict(visible=False, range=[PDF_IMG_H, 0]),  # y軸反転（PDF座標系）
        shapes=shapes,
        annotations=annotations,
    )
    return fig


def make_island_map(df, islands=None, target_machines=None, diff_override=None):
    """正規化済みExcel座標でPDF通りの島図を描画"""
    diff_map = {}
    for _, row in df.iterrows():
        if not np.isnan(row["台番"]):
            n = int(row["台番"])
            diff_map[n] = row["前日差枚"]
    if diff_override:
        for n, v in diff_override.items():
            diff_map[n] = v
    if target_machines is None:
        target_machines = set()

    # セルサイズ
    CW = 50   # セル幅
    CH = 36   # セル高
    PAD = 2

    shapes = []
    annotations = []

    for mno, (ex_row, ex_col) in MACHINE_POSITIONS.items():
        px = ex_col * CW
        py = -ex_row * CH  # y軸反転（上が小さい行番号）

        diff = diff_map.get(mno, np.nan)
        bg = diff_to_color(diff)
        text_c = diff_to_text_color(diff)
        is_target = mno in target_machines

        if np.isnan(diff):
            diff_text = "?"
        elif diff >= 0:
            diff_text = f"+{int(diff):,}"
        else:
            diff_text = f"{int(diff):,}"

        # 枠線色
        if is_target:
            border_c = "#ffffff"; border_w = 3
        elif not np.isnan(diff) and diff <= -500:
            border_c = "rgba(200,0,0,0.8)"; border_w = 1.5
        else:
            border_c = "rgba(80,80,80,0.5)"; border_w = 0.8

        # セル背景
        shapes.append(dict(type="rect",
            x0=px, y0=py - CH + PAD,
            x1=px + CW - PAD, y1=py,
            fillcolor=bg,
            line=dict(color=border_c, width=border_w),
            layer="below"))

        # 狙い台：金枠
        if is_target:
            shapes.append(dict(type="rect",
                x0=px - 3, y0=py - CH - 2,
                x1=px + CW + 2, y1=py + 3,
                fillcolor="rgba(0,0,0,0)",
                line=dict(color="#FFD700", width=2.5),
                layer="above"))
            annotations.append(dict(
                x=px + CW/2, y=py + 9,
                text="🎯", showarrow=False,
                font=dict(size=11), xanchor="center"))

        # 台番（上部）
        num_c = "#ffffff" if not np.isnan(diff) and diff >= 10000 else "rgba(0,0,0,0.6)"
        annotations.append(dict(
            x=px + CW/2, y=py - 8,
            text=str(mno),
            showarrow=False,
            font=dict(size=9, color=num_c),
            xanchor="center"))

        # 差枚（中央）
        annotations.append(dict(
            x=px + CW/2, y=py - CH/2 - 2,
            text=f"<b>{diff_text}</b>",
            showarrow=False,
            font=dict(size=10, color=text_c),
            xanchor="center"))

    # 全体サイズ
    all_px = [c * CW for _, (r, c) in MACHINE_POSITIONS.items()]
    all_py = [-r * CH for _, (r, c) in MACHINE_POSITIONS.items()]
    total_w = max(all_px) + CW * 3
    total_h = abs(min(all_py)) + CH * 3

    fig = go.Figure()
    fig.update_layout(
        width=max(1400, total_w),
        height=max(1200, total_h),
        paper_bgcolor="#0a0e1a",
        plot_bgcolor="#0d1520",
        showlegend=False,
        margin=dict(l=10, r=10, t=10, b=10),
        xaxis=dict(visible=False, range=[-CW, total_w]),
        yaxis=dict(visible=False, range=[min(all_py) - CH*2, CH*2]),
        hovermode="closest",
    )
    fig.update_layout(shapes=shapes, annotations=annotations)
    return fig


for key, val in [("stars",{}),("memos",{}),("active_filter","全台"),
                  ("df_main",None),("df_weekly",None),("last_updated",None),
                  ("islands",DEFAULT_ISLANDS)]:
    if key not in st.session_state:
        st.session_state[key] = val

def load_data():
    with st.spinner("データ取得中..."):
        df_raw, err = load_latest_sheet()
        if err:
            st.error(f"❌ {err}"); return
        df, wdf = process_df(df_raw)
        if df is None:
            st.error("❌ データの列が認識できませんでした"); return
        st.session_state.df_main = df
        st.session_state.df_weekly = wdf if wdf is not None else pd.DataFrame()
        st.session_state.last_updated = datetime.now().strftime("%H:%M")

if st.session_state.df_main is None:
    load_data()

